/**
 * salaries.js
 *
 * Salary and occupation data — loaded at build time from salaries.json.
 *
 * salaries.json is generated by scripts/fetch-salaries.js (GitHub Actions).
 * It pulls national annual mean wages from the BLS OES API for all 96 jobs.
 *
 * The MAJORS structure below defines the UI hierarchy (major → jobs).
 * The blsBase for each job is injected from salaries.json at build time,
 * so no salary figures are hardcoded in this file.
 */

import salariesData from './salaries.json' with { type: 'json' }

// Build a lookup map from jobId → blsBase wage
const wageMap = Object.fromEntries(
  salariesData.jobs.map(j => [j.jobId, j.blsBase])
)

// Helper: look up BLS wage for a job, throw clearly if missing
function wage(jobId) {
  const w = wageMap[jobId]
  if (!w) throw new Error(`No wage data for jobId "${jobId}" — re-run scripts/fetch-salaries.js`)
  return w
}

